// // Asynchronous reset synchronizes the flip-flop's state with the D input on the falling edge of the clock.
module d_flip_flop(
  input clk,
  input rst_n,
  input d,
  output reg q
);

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n)
      q <= 1'b0;
    else
      q <= d;
  end

endmodule
